// Script: generar_153_fix_perfil_selector.js
// 1) Quita headers duplicados del perfil (estaban en el perfil Y en los componentes)
//    Los Chiqui van ahora DENTRO de los componentes:
//    LinkVet → chiqui_doctor, GestionCotutor → chiqui_amor,
//    ConfiguracionNotificaciones → chiqui_estrella
// 2) Agrega "Perfil ›" en el SelectorMascota para acceder al perfil
//    directamente desde el cambiador de mascota en cualquier pantalla.

const fs = require('fs'); const path = require('path');
function png(r, b64) {
  const f = path.join(...r.split('/')); const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d,{recursive:true});
  fs.writeFileSync(f, Buffer.from(b64,'base64')); console.log('OK: '+f);
}
function tsx(r, b64) {
  const f = path.join(...r.split('/')); const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d,{recursive:true});
  fs.writeFileSync(f, Buffer.from(b64,'base64').toString('utf8')); console.log('OK: '+f);
}
png('public/chiqui/chiqui_ladeado.png', "");
tsx('components/SelectorMascota.tsx', "");
tsx('app/perfil/page.tsx', "");
tsx('components/LinkVet.tsx', "");
tsx('components/GestionCotutor.tsx', "");
tsx('components/ConfiguracionNotificaciones.tsx', "");
tsx('app/vet/page.tsx', "");
tsx('app/registro-diario/page.tsx', "");
